private Map<String, Integer> initializeHeader() throws IOException {
        Map<String, Integer> hdrMap = null;
        final String[] formatHeader = this.format.getHeader();
        if (formatHeader != null) {
            hdrMap = new LinkedHashMap<String, Integer>();

            String[] header = null;
            if (formatHeader.length == 0) {
                // read the header from the first line of the file
                final CSVRecord nextRecord = this.nextRecord();
                if (nextRecord != null) {
                    header = nextRecord.values();
                }
            } else {
                if (this.format.getSkipHeaderRecord()) {
                    this.nextRecord();
                }
                header = formatHeader;
            }

            // build the name to index mappings
            if (header != null) {
                for (int i = 0; i < Math.min(header.length, formatHeader.length); i++) {
                    if (hdrMap.containsKey(header[i])) {
                        throw new IllegalStateException("Duplicate header entries");
                    }
                    hdrMap.put(header[i], Integer.valueOf(i));
                }
            }

            // handle null and empty headers
            if (hdrMap != null) {
                if (hdrMap.isEmpty()) {
                    throw new IllegalStateException("No header entries");
                }
                if (hdrMap.size() != formatHeader.length) {
                    throw new IllegalStateException("Header entries do not match format header");
                }
            }
        }
        return hdrMap;
    }
